import{_ as o,H as r,f as s,i as a}from"./chunks/framework.Cvt1eIE0.js";const e="/store-locator/images/import-store.png",m=JSON.parse('{"title":"门店管理","description":"","frontmatter":{},"headers":[],"relativePath":"store-locator/guide/managing-stores.md","filePath":"store-locator/guide/managing-stores.md"}'),i={name:"store-locator/guide/managing-stores.md"};function n(l,t,g,u,d,h){return r(),s("div",null,[...t[0]||(t[0]=[a('<h1 id="门店管理" tabindex="-1">门店管理 <a class="header-anchor" href="#门店管理" aria-label="Permalink to &quot;门店管理&quot;">​</a></h1><p>在 Jika Store Locator 控制面板中高效管理您的实体门店。</p><h2 id="添加单家门店" tabindex="-1">添加单家门店 <a class="header-anchor" href="#添加单家门店" aria-label="Permalink to &quot;添加单家门店&quot;">​</a></h2><ol><li>导航到 <strong>Stores (门店)</strong> 页面，点击 <strong>Add Store (添加门店)</strong>。</li><li><strong>基本详情</strong>：提供门店名称、电话号码和网址。</li><li><strong>地址与坐标</strong>：手动填写或点击右上角<strong>pick from map</strong>使用在谷歌地图上找到您店铺的位置，自动带入相关信息。</li><li><strong>图片</strong>：上传一张门店图片，它会显示在列表和详情视图中。</li><li><strong>标签 (Tags)</strong>：分配标签（如 &quot;24/7&quot;, &quot;支持路边自提&quot;）来帮助客户筛选门店。</li><li><strong>自定义字段</strong>：添加任何额外数据，如 &quot;店长姓名&quot; 或 &quot;特色服务&quot;。</li></ol><h2 id="门店属性-store-attributes" tabindex="-1">门店属性 (Store Attributes) <a class="header-anchor" href="#门店属性-store-attributes" aria-label="Permalink to &quot;门店属性 (Store Attributes)&quot;">​</a></h2><p>通过 <strong>标签</strong> 和 <strong>自定义字段</strong>，您可以让门店信息更加丰富，并为客户提供更精准的筛选体验。</p><h3 id="_1-标签-tags" tabindex="-1">1. 标签 (Tags) <a class="header-anchor" href="#_1-标签-tags" aria-label="Permalink to &quot;1. 标签 (Tags)&quot;">​</a></h3><p>标签用于对门店进行分类（如：支持维修、24小时营业、有停车位等）。</p><ul><li><strong>全局管理</strong>：进入 <strong>Settings &gt; Store Attributes</strong>。在这里您可以创建、修改或删除全局标签。</li><li><strong>分配标签</strong>：在添加或编辑门店时，从右侧边栏的 <strong>Tags</strong> 下拉框中选择现有标签，或直接输入新标签并点击 <strong>Create</strong>。</li><li><strong>前端作用</strong>：开启标签功能后，前台地图会自动显示标签筛选列表，方便用户快速找到符合条件的门店。</li></ul><h3 id="_2-自定义字段-custom-fields" tabindex="-1">2. 自定义字段 (Custom Fields) <a class="header-anchor" href="#_2-自定义字段-custom-fields" aria-label="Permalink to &quot;2. 自定义字段 (Custom Fields)&quot;">​</a></h3><p>如果系统自带的字段（名称、地址、电话等）不够用，您可以自定义额外的字段（如：店长姓名、商场楼层、店内促销信息等）。</p><ul><li><strong>定义字段类型</strong>：进入 <strong>Settings &gt; Store Attributes</strong> 的 <strong>Custom Field</strong> 区块。</li><li><strong>添加定义</strong>：点击 <strong>Add Field</strong>，输入字段名称（如 &quot;楼层&quot;）。</li><li><strong>填写数据</strong>：定义好之后，在添加或编辑门店时，右侧边栏会自动出现这些字段，供您为每家店填写具体内容。</li><li><strong>前端显示</strong>：填写了内容的自定义字段会自动展示在前台商店详情的列表下方。</li></ul><h2 id="批量导入门店" tabindex="-1">批量导入门店 <a class="header-anchor" href="#批量导入门店" aria-label="Permalink to &quot;批量导入门店&quot;">​</a></h2><p>如果您有大量门店，可以使用 CSV 文件进行批量导入。</p><ol><li>导航到 <strong>Stores &gt; Import</strong>。 <img src="'+e+'" alt="批量导入"></li><li>下载我们的 <strong>CSV 模板</strong> 以确保数据格式正确。</li><li>上传您填好的 CSV 文件。</li><li>预览数据并点击 <strong>Start Import (开始导入)</strong>。</li></ol><h2 id="门店状态" tabindex="-1">门店状态 <a class="header-anchor" href="#门店状态" aria-label="Permalink to &quot;门店状态&quot;">​</a></h2><ul><li><strong>Active (启用)</strong>：门店对前端客户可见。</li><li><strong>Inactive (禁用)</strong>：门店在前端隐藏，但仍保留在后台供您管理。</li></ul><h2 id="门店类型" tabindex="-1">门店类型 <a class="header-anchor" href="#门店类型" aria-label="Permalink to &quot;门店类型&quot;">​</a></h2><ul><li><strong>Offline (线下店)</strong>：标准的实体门店。</li><li><strong>Online (线上/展示店)</strong>：纯在线存在或虚拟办公室（可根据需要配置筛选）。</li></ul>',19)])])}const p=o(i,[["render",n]]);export{m as __pageData,p as default};
